const anomalySeverity = $input.first().json.anomaly_severity;
const componentId = $input.first().json.component_id;
const confidenceScore = $input.first().json.confidence_score;

// RUL calculation based on severity
const rulMapping = {
  'critical': 7,
  'high': 30,
  'medium': 90,
  'low': 180
};

const baseRUL = rulMapping[anomalySeverity] || 90;
const adjustedRUL = Math.round(baseRUL * confidenceScore);

const predictedFailureDate = new Date();
predictedFailureDate.setDate(predictedFailureDate.getDate() + adjustedRUL);

return {
  remaining_useful_life_days: adjustedRUL,
  predicted_failure_date: predictedFailureDate.toISOString().split('T')[0],
  calculation_timestamp: new Date().toISOString()
};

const items = $input.all();
const auditLog = [];

for (const item of items) {
  const record = {
    audit_id: `AUDIT-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    timestamp: new Date().toISOString(),
    vehicle_id: item.json.vehicle_id,
    component_id: item.json.component_id,
    anomaly_detected: item.json.anomaly_detected,
    predicted_failure_date: item.json.predicted_failure_date || null,
    remaining_useful_life_days: item.json.remaining_useful_life_days || null,
    recommended_action: item.json.recommended_action,
    urgency_level: item.json.urgency_level,
    confidence_score: item.json.confidence_score,
    maintenance_priority: item.json.maintenance_priority || null,
    alert_type: item.json.alert_type,
    notification_required: item.json.notification_required,
    escalation_level: item.json.escalation_level,
    workflow_execution_id: $execution.id,
    data_sources: ['real-time_telemetry', 'historical_data'],
    ai_agents_used: ['anomaly_detection_agent', 'maintenance_prioritization_agent'],
    audit_trail: {
      processed_at: item.json.timestamp,
      workflow_name: $workflow.name,
      deterministic: true,
      compliance_ready: true
    }
  };

  auditLog.push(record);
}

return auditLog.map(log => ({ json: log }));
